import re

def norm_doc(d):
    return re.sub(r"[^a-z0-9]", "", d.casefold())

def blocking_key(rec):
    parts = rec.get("name", "").split()
    ap = parts[1].casefold() if len(parts) > 1 else (parts[0].casefold() if parts else "")
    return f"{ap}|{rec.get('region','').casefold()}"

def er_score(a, b):
    if norm_doc(a.get("doc", "")) == norm_doc(b.get("doc", "")) and blocking_key(a) == blocking_key(b):
        return 1.0
    return 0.5  # reglas deterministas stdlib; sin ML

a = {"name": "Luis Huamán", "region": "Cusco", "doc": "D-1"}
b = {"name": "Luis Huamán", "region": "Cusco", "doc": "D1"}
print(er_score(a, b))
print("memo: 1.0 solo con doc normalizado igual y mismo blocking_key; si no 0.5 determinista")

def shared_email(a, b):
    ea, eb = (a or "").casefold().strip(), (b or "").casefold().strip()
    if not ea or not eb:
        return False
    return ea == eb

print(shared_email("A@x.com", "a@x.com"), "|", shared_email("", "a@x.com"), "|", shared_email("a@x.com", "b@x.com"))

def rel_score(km, surname_jaccard):
    geo = 1.0 if km < 2 else 0.0
    return round(0.6 * geo + 0.4 * surname_jaccard, 3)

print(rel_score(1.0, 0.5), "|", rel_score(5.0, 0.5))

def direct_txs(txs, a, b):
    out = []
    for t in txs:
        if {t["from"], t["to"]} == {a, b}:
            out.append(t["monto"])
    return out

txs = [
    {"from": "A", "to": "B", "monto": 10},
    {"from": "B", "to": "A", "monto": 5},
    {"from": "A", "to": "C", "monto": 7},
]
print(direct_txs(txs, "A", "B"))

def common_counterparties(txs, a, c):
    touch = {a: set(), c: set()}
    for t in txs:
        fr, to = t["from"], t["to"]
        if fr in touch:
            touch[fr].add(to)
        if to in touch:
            touch[to].add(fr)
    return sorted(touch[a] & touch[c])

txs = [
    {"from": "A", "to": "X", "monto": 1},
    {"from": "C", "to": "X", "monto": 1},
    {"from": "A", "to": "Y", "monto": 1},
]
print(common_counterparties(txs, "A", "C"))

def uncertainty_band(missing, conflict):
    if conflict or len(missing) >= 2:
        return "high"
    if missing:
        return "med"
    return "low"

print(uncertainty_band([], False), "|", uncertainty_band(["a"], False), "|", uncertainty_band(["a", "b"], False), "|", uncertainty_band([], True))

def decide(score, uncertainty, valid=True, review_low=0.4, accept_min=0.8):
    if not valid:
        return "invalid_input"
    if uncertainty == "high":
        return "needs_review"
    if score < review_low:
        return "abstain"
    if score < accept_min:
        return "needs_review"
    return "accept_candidate"

print(decide(0.9, "low"))
print(decide(0.5, "low"))
print(decide(0.2, "low"))
print(decide(0.9, "high"))
print(decide(0.9, "low", valid=False))

out = {"score": 0.5, "status": "needs_review", "is_family": True, "auto_fraud": False}
for k in ("is_family", "auto_fraud"):
    out.pop(k, None)
print(sorted(out.keys()))

def pseudonymize(full: str) -> str:
    parts = full.split()
    return " ".join((p[0] + "***") for p in parts if p)

print(pseudonymize("Ana Quispe Rojas"))

def case_sheet(er, rel):
    sheet = {
        "entity_resolution_score": er,
        "relationship_signal_score": rel,
    }
    assert "entity_resolution_score" in sheet and "relationship_signal_score" in sheet
    assert list(sheet)[0] != list(sheet)[1]
    return sheet

